     1→//! BIDS layout and query implementation
     2→//!
     3→//! This module provides functionality for parsing BIDS entities
     4→//! and querying templates based on BIDS conventions.
     5→
     6→use crate::error::{Result, TemplateFlowError};
     7→use serde::{Deserialize, Serialize};
     8→use serde_json::Value;
     9→use std::collections::HashMap;
    10→use std::path::{Path, PathBuf};
    11→
    12→/// BIDS entities that can be present in a filename
    13→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
    14→pub enum BidsEntity {
    15→    Template,
    16→    Resolution,
    17→    Density,
    18→    Atlas,
    19→    Suffix,
    20→    Description,
    21→    Extension,
    22→    Label,
    23→    Segmentation,
    24→    Hemisphere,
    25→    Space,
    26→}
    27→
    28→impl BidsEntity {
    29→    /// Get the short form used in filenames (e.g., "res" for Resolution)
    30→    pub fn key(&self) -> &'static str {
    31→        match self {
    32→            BidsEntity::Template => "tpl",
    33→            BidsEntity::Resolution => "res",
    34→            BidsEntity::Density => "den",
    35→            BidsEntity::Atlas => "atlas",
    36→            BidsEntity::Suffix => "suffix",
    37→            BidsEntity::Description => "desc",
    38→            BidsEntity::Extension => "ext",
    39→            BidsEntity::Label => "label",
    40→            BidsEntity::Segmentation => "seg",
    41→            BidsEntity::Hemisphere => "hemi",
    42→            BidsEntity::Space => "space",
    43→        }
    44→    }
    45→
    46→    /// Parse from a key string
    47→    pub fn from_key(key: &str) -> Option<Self> {
    48→        match key {
    49→            "tpl" => Some(BidsEntity::Template),
    50→            "res" => Some(BidsEntity::Resolution),
    51→            "den" => Some(BidsEntity::Density),
    52→            "atlas" => Some(BidsEntity::Atlas),
    53→            "suffix" => Some(BidsEntity::Suffix),
    54→            "desc" => Some(BidsEntity::Description),
    55→            "ext" => Some(BidsEntity::Extension),
    56→            "label" => Some(BidsEntity::Label),
    57→            "seg" => Some(BidsEntity::Segmentation),
    58→            "hemi" => Some(BidsEntity::Hemisphere),
    59→            "space" => Some(BidsEntity::Space),
    60→            _ => None,
    61→        }
    62→    }
    63→}
    64→
    65→/// Template metadata from template_description.json
    66→///
    67→/// This structure contains metadata about a brain template including its name,
    68→/// description, authors, license, and relevant publications. The metadata follows
    69→/// the BIDS specification for template descriptions.
    70→///
    71→/// # Example
    72→/// ```no_run
    73→/// use templateflow::get_metadata;
    74→///
    75→/// let metadata = get_metadata("MNI152Lin").unwrap();
    76→/// println!("Template: {}", metadata.name);
    77→/// println!("Authors: {}", metadata.authors.join(", "));
    78→/// if let Some(desc) = &metadata.description {
    79→///     println!("Description: {}", desc);
    80→/// }
    81→/// ```
    82→#[derive(Debug, Clone, Serialize, Deserialize)]
    83→#[serde(rename_all = "PascalCase")]
    84→pub struct TemplateMetadata {
    85→    /// Template identifier (e.g., "MNI152Lin")
    86→    #[serde(rename = "Identifier")]
    87→    pub identifier: Option<String>,
    88→    
    89→    /// Full name of the template
    90→    #[serde(rename = "Name")]
    91→    pub name: String,
    92→    
    93→    /// Description of the template
    94→    #[serde(rename = "Description")]
    95→    pub description: Option<String>,
    96→    
    97→    /// Native coordinate system (e.g., "MNI152Lin")
    98→    #[serde(rename = "NativeCoordinateSystem")]
    99→    pub native_coord_system: Option<String>,
   100→    
   101→    /// List of authors
   102→    #[serde(rename = "Authors", default)]
   103→    pub authors: Vec<String>,
   104→    
   105→    /// License information
   106→    #[serde(rename = "License")]
   107→    pub license: Option<String>,
   108→    
   109→    /// List of references and links
   110→    #[serde(rename = "ReferencesAndLinks", default)]
   111→    pub references_and_links: Vec<Value>,
   112→    
   113→    /// URL to the template
   114→    #[serde(rename = "URL")]
   115→    pub url: Option<String>,
   116→    
   117→    /// DOI of the template
   118→    #[serde(rename = "DOI")]
   119→    pub doi: Option<String>,
   120→    
   121→    /// Version of the template
   122→    #[serde(rename = "Version")]
   123→    pub version: Option<String>,
   124→    
   125→    /// Research Resource Identifier
   126→    #[serde(rename = "RRID")]
   127→    pub rrid: Option<String>,
   128→    
   129→    /// Species (e.g., "Homo sapiens")
   130→    #[serde(rename = "Species")]
   131→    pub species: Option<String>,
   132→    
   133→    /// Any additional fields not explicitly defined
   134→    #[serde(flatten)]
   135→    pub extra: HashMap<String, Value>,
   136→}
   137→
   138→impl TemplateMetadata {
   139→    /// Parse metadata from JSON string
   140→    pub fn from_json(json: &str) -> Result<Self> {
   141→        serde_json::from_str(json)
   142→            .map_err(|e| TemplateFlowError::InvalidEntity(format!("Invalid metadata JSON: {}", e)))
   143→    }
   144→    
   145→    /// Parse metadata from a file
   146→    pub fn from_file(path: &Path) -> Result<Self> {
   147→        let content = std::fs::read_to_string(path)?;
   148→        Self::from_json(&content)
   149→    }
   150→}
   151→
   152→/// A single file in the template layout
   153→#[derive(Debug, Clone, Serialize, Deserialize)]
   154→pub struct TemplateFile {
   155→    /// Full path to the file
   156→    pub path: PathBuf,
   157→    /// Template name
   158→    pub template: String,
   159→    /// BIDS entities extracted from the filename
   160→    pub entities: HashMap<String, String>,
   161→    /// File suffix (e.g., "T1w", "mask", "dseg")
   162→    pub suffix: Option<String>,
   163→    /// File extension (e.g., "nii.gz", "json", "tsv")
   164→    pub extension: Option<String>,
   165→}
   166→
   167→impl TemplateFile {
   168→    /// Create a new TemplateFile by parsing a path
   169→    pub fn from_path(path: &Path) -> Result<Self> {
   170→        let filename = path
   171→            .file_name()
   172→            .and_then(|n| n.to_str())
   173→            .ok_or_else(|| TemplateFlowError::InvalidEntity("Invalid filename".to_string()))?;
   174→
   175→        let entities = parse_entities(filename)?;
   176→        
   177→        let template = entities
   178→            .get("tpl")
   179→            .ok_or_else(|| TemplateFlowError::InvalidEntity("Missing template entity".to_string()))?
   180→            .clone();
   181→
   182→        let suffix = extract_suffix(filename);
   183→        let extension = extract_extension(filename);
   184→
   185→        Ok(TemplateFile {
   186→            path: path.to_path_buf(),
   187→            template,
   188→            entities,
   189→            suffix,
   190→            extension,
   191→        })
   192→    }
   193→
   194→    /// Check if this file matches the given query parameters
   195→    pub fn matches(&self, query: &HashMap<String, String>) -> bool {
   196→        for (key, value) in query {
   197→            match key.as_str() {
   198→                "suffix" => {
   199→                    if self.suffix.as_ref() != Some(value) {
   200→                        return false;
   201→                    }
   202→                }
   203→                "extension" => {
   204→                    if self.extension.as_ref() != Some(value) {
   205→                        return false;
   206→                    }
   207→                }
   208→                _ => {
   209→                    if self.entities.get(key) != Some(value) {
   210→                        return false;
   211→                    }
   212→                }
   213→            }
   214→        }
   215→        true
   216→    }
   217→}
   218→
   219→/// Parse BIDS entities from a filename
   220→fn parse_entities(filename: &str) -> Result<HashMap<String, String>> {
   221→    let mut entities = HashMap::new();
   222→    
   223→    // Remove extension(s) to get the base name
   224→    let base = filename.split('.').next().unwrap_or(filename);
   225→    
   226→    // Split by underscore to get entity pairs
   227→    let parts: Vec<&str> = base.split('_').collect();
   228→    
   229→    for part in parts {
   230→        if let Some(dash_pos) = part.find('-') {
   231→            let key = &part[..dash_pos];
   232→            let value = &part[dash_pos + 1..];
   233→            
   234→            // Validate that this is a known entity
   235→            if BidsEntity::from_key(key).is_some() {
   236→                entities.insert(key.to_string(), value.to_string());
   237→            }
   238→        }
   239→    }
   240→    
   241→    Ok(entities)
   242→}
   243→
   244→/// Extract the suffix from a filename (last part after underscore, before extension)
   245→fn extract_suffix(filename: &str) -> Option<String> {
   246→    // Remove extensions
   247→    let base = filename.split('.').next()?;
   248→    
   249→    // Get the last part after underscore
   250→    let parts: Vec<&str> = base.split('_').collect();
   251→    let last_part = parts.last()?;
   252→    
   253→    // If it doesn't contain a dash, it's likely a suffix
   254→    if !last_part.contains('-') {
   255→        Some(last_part.to_string())
   256→    } else {
   257→        None
   258→    }
   259→}
   260→
   261→/// Extract the extension(s) from a filename (e.g., "nii.gz", "json")
   262→fn extract_extension(filename: &str) -> Option<String> {
   263→    if let Some(dot_pos) = filename.find('.') {
   264→        Some(filename[dot_pos + 1..].to_string())
   265→    } else {
   266→        None
   267→    }
   268→}
   269→
   270→/// Template layout containing all files for available templates
   271→#[derive(Debug, Default, Serialize, Deserialize)]
   272→pub struct TemplateLayout {
   273→    /// Map from template name to list of files
   274→    pub templates: HashMap<String, Vec<TemplateFile>>,
   275→    
   276→    /// Map from template name to metadata
   277→    pub metadata: HashMap<String, TemplateMetadata>,
   278→}
   279→
   280→impl TemplateLayout {
   281→    /// Create a new empty layout
   282→    pub fn new() -> Self {
   283→        Self::default()
   284→    }
   285→
   286→    /// Add a file to the layout
   287→    pub fn add_file(&mut self, file: TemplateFile) {
   288→        self.templates
   289→            .entry(file.template.clone())
   290→            .or_insert_with(Vec::new)
   291→            .push(file);
   292→    }
   293→
   294→    /// Get all templates
   295→    pub fn get_templates(&self) -> Vec<&str> {
   296→        self.templates.keys().map(|s| s.as_str()).collect()
   297→    }
   298→
   299→    /// Get files for a specific template
   300→    pub fn get_template_files(&self, template: &str) -> Option<&[TemplateFile]> {
   301→        self.templates.get(template).map(|v| v.as_slice())
   302→    }
   303→
   304→    /// Query files across all templates
   305→    pub fn query(&self, query: &HashMap<String, String>) -> Vec<&TemplateFile> {
   306→        let mut results = Vec::new();
   307→        
   308→        // If template is specified in query, only search that template
   309→        if let Some(template) = query.get("tpl") {
   310→            if let Some(files) = self.templates.get(template) {
   311→                for file in files {
   312→                    if file.matches(query) {
   313→                        results.push(file);
   314→                    }
   315→                }
   316→            }
   317→        } else {
   318→            // Search all templates
   319→            for files in self.templates.values() {
   320→                for file in files {
   321→                    if file.matches(query) {
   322→                        results.push(file);
   323→                    }
   324→                }
   325→            }
   326→        }
   327→        
   328→        results
   329→    }
   330→    
   331→    /// Add metadata for a template
   332→    pub fn add_metadata(&mut self, template: &str, metadata: TemplateMetadata) {
   333→        self.metadata.insert(template.to_string(), metadata);
   334→    }
   335→    
   336→    /// Get metadata for a specific template
   337→    pub fn get_metadata(&self, template: &str) -> Option<&TemplateMetadata> {
   338→        self.metadata.get(template)
   339→    }
   340→}
   341→
   342→/// Parse the templateflow skeleton from a zip file
   343→pub fn parse_skeleton<R: std::io::Read + std::io::Seek>(reader: R) -> Result<TemplateLayout> {
   344→    use zip::ZipArchive;
   345→    use std::io::Read;
   346→    
   347→    let mut archive = ZipArchive::new(reader)
   348→        .map_err(|e| TemplateFlowError::IoError(e.into()))?;
   349→    
   350→    let mut layout = TemplateLayout::new();
   351→    let mut metadata_files = HashMap::new();
   352→    
   353→    // First pass: collect all files and metadata
   354→    for i in 0..archive.len() {
   355→        let mut file = archive.by_index(i)
   356→            .map_err(|e| TemplateFlowError::IoError(e.into()))?;
   357→        
   358→        let path = PathBuf::from(file.name());
   359→        
   360→        // Skip directories
   361→        if file.is_dir() {
   362→            continue;
   363→        }
   364→        
   365→        // Check if path is within a template directory
   366→        let components: Vec<_> = path.components().collect();
   367→        if components.is_empty() {
   368→            continue;
   369→        }
   370→        
   371→        // Get the first component (should be template directory)
   372→        let first_component = components[0].as_os_str().to_str().unwrap_or("");
   373→        if !first_component.starts_with("tpl-") {
   374→            continue;
   375→        }
   376→        
   377→        // Check if this is a template_description.json file
   378→        if path.file_name() == Some(std::ffi::OsStr::new("template_description.json")) {
   379→            // Extract template name from parent directory
   380→            if let Some(parent) = path.parent() {
   381→                if let Some(parent_name) = parent.file_name() {
   382→                    if let Some(template_name) = parent_name.to_str() {
   383→                        if template_name.starts_with("tpl-") {
   384→                            let template = template_name.strip_prefix("tpl-").unwrap();
   385→                            let mut content = String::new();
   386→                            file.read_to_string(&mut content)
   387→                                .map_err(|e| TemplateFlowError::IoError(e))?;
   388→                            metadata_files.insert(template.to_string(), content);
   389→                        }
   390→                    }
   391→                }
   392→            }
   393→        } else {
   394→            // Try to parse as a template file
   395→            match TemplateFile::from_path(&path) {
   396→                Ok(template_file) => {
   397→                    layout.add_file(template_file);
   398→                }
   399→                Err(_) => {
   400→                    // Skip files that don't parse as valid BIDS files
   401→                    continue;
   402→                }
   403→            }
   404→        }
   405→    }
   406→    
   407→    // Second pass: parse metadata files
   408→    for (template, json_content) in metadata_files {
   409→        match TemplateMetadata::from_json(&json_content) {
   410→            Ok(metadata) => {
   411→                layout.add_metadata(&template, metadata);
   412→            }
   413→            Err(e) => {
   414→                // Log error but don't fail the entire parsing
   415→                eprintln!("Failed to parse metadata for template {}: {}", template, e);
   416→            }
   417→        }
   418→    }
   419→    
   420→    Ok(layout)
   421→}
   422→
   423→/// Load the skeleton from a file path
   424→pub fn load_skeleton_from_file(path: &Path) -> Result<TemplateLayout> {
   425→    use std::fs::File;
   426→    
   427→    let file = File::open(path)?;
   428→    parse_skeleton(file)
   429→}
   430→
   431→/// Load the skeleton from bytes
   432→pub fn load_skeleton_from_bytes(bytes: &[u8]) -> Result<TemplateLayout> {
   433→    use std::io::Cursor;
   434→    
   435→    let cursor = Cursor::new(bytes);
   436→    parse_skeleton(cursor)
   437→}
   438→
   439→#[cfg(test)]
   440→mod tests {
   441→    use super::*;
   442→
   443→    #[test]
   444→    fn test_parse_entities() {
   445→        let filename = "tpl-MNI152NLin2009cAsym_res-01_desc-brain_T1w.nii.gz";
   446→        let entities = parse_entities(filename).unwrap();
   447→        
   448→        assert_eq!(entities.get("tpl"), Some(&"MNI152NLin2009cAsym".to_string()));
   449→        assert_eq!(entities.get("res"), Some(&"01".to_string()));
   450→        assert_eq!(entities.get("desc"), Some(&"brain".to_string()));
   451→    }
   452→
   453→    #[test]
   454→    fn test_extract_suffix() {
   455→        assert_eq!(
   456→            extract_suffix("tpl-MNI152Lin_res-01_T1w.nii.gz"),
   457→            Some("T1w".to_string())
   458→        );
   459→        assert_eq!(
   460→            extract_suffix("tpl-MNI152Lin_res-01_desc-brain_mask.nii.gz"),
   461→            Some("mask".to_string())
   462→        );
   463→        assert_eq!(
   464→            extract_suffix("tpl-MNI152Lin_res-01_label-GM_probseg.nii.gz"),
   465→            Some("probseg".to_string())
   466→        );
   467→    }
   468→
   469→    #[test]
   470→    fn test_extract_extension() {
   471→        assert_eq!(
   472→            extract_extension("file.nii.gz"),
   473→            Some("nii.gz".to_string())
   474→        );
   475→        assert_eq!(
   476→            extract_extension("template_description.json"),
   477→            Some("json".to_string())
   478→        );
   479→        assert_eq!(extract_extension("no_extension"), None);
   480→    }
   481→
   482→    #[test]
   483→    fn test_template_file_matches() {
   484→        let file = TemplateFile {
   485→            path: PathBuf::from("tpl-MNI152Lin_res-01_T1w.nii.gz"),
   486→            template: "MNI152Lin".to_string(),
   487→            entities: HashMap::from([
   488→                ("tpl".to_string(), "MNI152Lin".to_string()),
   489→                ("res".to_string(), "01".to_string()),
   490→            ]),
   491→            suffix: Some("T1w".to_string()),
   492→            extension: Some("nii.gz".to_string()),
   493→        };
   494→
   495→        let query1 = HashMap::from([("res".to_string(), "01".to_string())]);
   496→        assert!(file.matches(&query1));
   497→
   498→        let query2 = HashMap::from([
   499→            ("res".to_string(), "01".to_string()),
   500→            ("suffix".to_string(), "T1w".to_string()),
   501→        ]);
   502→        assert!(file.matches(&query2));
   503→
   504→        let query3 = HashMap::from([("res".to_string(), "02".to_string())]);
   505→        assert!(!file.matches(&query3));
   506→    }
   507→
   508→    #[test]
   509→    fn test_parse_skeleton() {
   510→        // Test with actual skeleton file if it exists
   511→        let skel_path = std::path::Path::new("../python-client/templateflow/conf/templateflow-skel.zip");
   512→        assert!(skel_path.exists(), "Skeleton file not found at {:?}", skel_path);
   513→        {
   514→            let layout = load_skeleton_from_file(skel_path).unwrap();
   515→            
   516→            // Check that we have some templates
   517→            assert!(!layout.templates.is_empty());
   518→            
   519→            // Check a known template exists
   520→            assert!(layout.get_template_files("MNI152Lin").is_some());
   521→            
   522→            // Test querying
   523→            let query = HashMap::from([
   524→                ("tpl".to_string(), "MNI152Lin".to_string()),
   525→                ("suffix".to_string(), "T1w".to_string()),
   526→            ]);
   527→            let results = layout.query(&query);
   528→            assert!(!results.is_empty());
   529→            
   530→            // Test metadata
   531→            println!("Total templates with metadata: {}", layout.metadata.len());
   532→            if let Some(metadata) = layout.get_metadata("MNI152Lin") {
   533→                assert!(!metadata.name.is_empty());
   534→                println!("MNI152Lin metadata: {:?}", metadata);
   535→            } else {
   536→                println!("No metadata found for MNI152Lin");
   537→            }
   538→        }
   539→    }
   540→    
   541→    #[test]
   542→    fn test_template_metadata_parsing() {
   543→        let json = r#"{
   544→            "Name": "Linear ICBM Average Brain (ICBM152) Stereotaxic Registration Model",
   545→            "Description": "The ICBM152 stereotaxic template for MNI space",
   546→            "Identifier": "MNI152Lin",
   547→            "License": "See LICENSE file",
   548→            "Authors": ["Evans, A.C.", "Collins, D.L.", "Mills, S.R."],
   549→            "ReferencesAndLinks": [
   550→                {
   551→                    "Reference": "Evans et al. 1992",
   552→                    "URL": "https://doi.org/10.1234/example"
   553→                }
   554→            ],
   555→            "Species": "Homo sapiens"
   556→        }"#;
   557→        
   558→        let metadata = TemplateMetadata::from_json(json).unwrap();
   559→        assert_eq!(metadata.name, "Linear ICBM Average Brain (ICBM152) Stereotaxic Registration Model");
   560→        assert_eq!(metadata.identifier, Some("MNI152Lin".to_string()));
   561→        assert_eq!(metadata.authors.len(), 3);
   562→        assert_eq!(metadata.species, Some("Homo sapiens".to_string()));
   563→    }
   564→}

