//! Optimized BIDS layout and query implementation
//!
//! This module provides high-performance functionality for parsing BIDS entities
//! and querying templates based on BIDS conventions using optimized data structures.

use crate::error::{Result, TemplateFlowError};
use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::collections::{HashMap, HashSet};
use std::path::{Path, PathBuf};
use std::sync::Arc;

/// BIDS entities that can be present in a filename
#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub enum BidsEntity {
    Template,
    Resolution,
    Density,
    Atlas,
    Suffix,
    Description,
    Extension,
    Label,
    Segmentation,
    Hemisphere,
    Space,
}

/// Static mapping for entity keys to avoid allocations
static ENTITY_KEY_MAP: &[(&str, BidsEntity)] = &[
    ("tpl", BidsEntity::Template),
    ("res", BidsEntity::Resolution),
    ("den", BidsEntity::Density),
    ("atlas", BidsEntity::Atlas),
    ("suffix", BidsEntity::Suffix),
    ("desc", BidsEntity::Description),
    ("ext", BidsEntity::Extension),
    ("label", BidsEntity::Label),
    ("seg", BidsEntity::Segmentation),
    ("hemi", BidsEntity::Hemisphere),
    ("space", BidsEntity::Space),
];

impl BidsEntity {
    /// Get the short form used in filenames (e.g., "res" for Resolution)
    #[inline]
    pub fn key(&self) -> &'static str {
        match self {
            BidsEntity::Template => "tpl",
            BidsEntity::Resolution => "res",
            BidsEntity::Density => "den",
            BidsEntity::Atlas => "atlas",
            BidsEntity::Suffix => "suffix",
            BidsEntity::Description => "desc",
            BidsEntity::Extension => "ext",
            BidsEntity::Label => "label",
            BidsEntity::Segmentation => "seg",
            BidsEntity::Hemisphere => "hemi",
            BidsEntity::Space => "space",
        }
    }

    /// Parse from a key string using static lookup
    #[inline]
    pub fn from_key(key: &str) -> Option<Self> {
        ENTITY_KEY_MAP
            .iter()
            .find(|(k, _)| *k == key)
            .map(|(_, entity)| entity.clone())
    }
}

/// Template metadata from template_description.json
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "PascalCase")]
pub struct TemplateMetadata {
    #[serde(rename = "Identifier")]
    pub identifier: Option<String>,

    #[serde(rename = "Name")]
    pub name: String,

    #[serde(rename = "Description")]
    pub description: Option<String>,

    #[serde(rename = "NativeCoordinateSystem")]
    pub native_coord_system: Option<String>,

    #[serde(rename = "Authors", default)]
    pub authors: Vec<String>,

    #[serde(rename = "License")]
    pub license: Option<String>,

    #[serde(rename = "ReferencesAndLinks", default)]
    pub references_and_links: Vec<Value>,

    #[serde(rename = "URL")]
    pub url: Option<String>,

    #[serde(rename = "DOI")]
    pub doi: Option<String>,

    #[serde(rename = "Version")]
    pub version: Option<String>,

    #[serde(rename = "RRID")]
    pub rrid: Option<String>,

    #[serde(rename = "Species")]
    pub species: Option<String>,

    #[serde(flatten)]
    pub extra: HashMap<String, Value>,
}

impl TemplateMetadata {
    /// Parse metadata from JSON string
    pub fn from_json(json: &str) -> Result<Self> {
        serde_json::from_str(json)
            .map_err(|e| TemplateFlowError::InvalidEntity(format!("Invalid metadata JSON: {}", e)))
    }

    /// Parse metadata from a file
    pub fn from_file(path: &Path) -> Result<Self> {
        let content = std::fs::read_to_string(path)?;
        Self::from_json(&content)
    }
}

/// A single file in the template layout with optimized storage
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TemplateFile {
    /// Full path to the file
    pub path: Arc<PathBuf>,
    /// Template name (interned string for memory efficiency)
    pub template: Arc<str>,
    /// BIDS entities extracted from the filename (using Arc for shared ownership)
    pub entities: Arc<HashMap<String, String>>,
    /// File suffix (e.g., "T1w", "mask", "dseg")
    pub suffix: Option<Arc<str>>,
    /// File extension (e.g., "nii.gz", "json", "tsv")
    pub extension: Option<Arc<str>>,
}

impl TemplateFile {
    /// Create a new TemplateFile by parsing a path
    pub fn from_path(path: &Path) -> Result<Self> {
        let filename = path
            .file_name()
            .and_then(|n| n.to_str())
            .ok_or_else(|| TemplateFlowError::InvalidEntity("Invalid filename".to_string()))?;

        let entities = parse_entities_optimized(filename)?;

        let template = entities
            .get("tpl")
            .ok_or_else(|| TemplateFlowError::InvalidEntity("Missing template entity".to_string()))?
            .clone();

        let suffix = extract_suffix(filename).map(|s| Arc::from(s.as_str()));
        let extension = extract_extension(filename).map(|s| Arc::from(s.as_str()));

        Ok(TemplateFile {
            path: Arc::new(path.to_path_buf()),
            template: Arc::from(template.as_str()),
            entities: Arc::new(entities),
            suffix,
            extension,
        })
    }

    /// Check if this file matches the given query parameters (optimized)
    #[inline]
    pub fn matches(&self, query: &HashMap<String, String>) -> bool {
        query.iter().all(|(key, value)| {
            match key.as_str() {
                "suffix" => self.suffix.as_ref().map(|s| s.as_ref()) == Some(value.as_str()),
                "extension" => self.extension.as_ref().map(|s| s.as_ref()) == Some(value.as_str()),
                _ => self.entities.get(key).map(|s| s.as_str()) == Some(value.as_str()),
            }
        })
    }
}

/// Parse BIDS entities from a filename with optimizations
fn parse_entities_optimized(filename: &str) -> Result<HashMap<String, String>> {
    let mut entities = HashMap::with_capacity(8); // Pre-allocate reasonable capacity

    // Remove extension(s) to get the base name
    let base = filename.split('.').next().unwrap_or(filename);

    // Split by underscore to get entity pairs
    for part in base.split('_') {
        if let Some(dash_pos) = part.find('-') {
            let key = &part[..dash_pos];
            let value = &part[dash_pos + 1..];

            // Validate that this is a known entity
            if BidsEntity::from_key(key).is_some() {
                entities.insert(key.to_string(), value.to_string());
            }
        }
    }

    Ok(entities)
}

/// Extract the suffix from a filename (last part after underscore, before extension)
fn extract_suffix(filename: &str) -> Option<String> {
    let base = filename.split('.').next()?;
    let parts: Vec<&str> = base.split('_').collect();
    let last_part = parts.last()?;

    if !last_part.contains('-') {
        Some(last_part.to_string())
    } else {
        None
    }
}

/// Extract the extension(s) from a filename (e.g., "nii.gz", "json")
fn extract_extension(filename: &str) -> Option<String> {
    filename.find('.').map(|dot_pos| filename[dot_pos + 1..].to_string())
}

/// Index for a single entity value to file mappings
type EntityIndex = HashMap<String, Vec<usize>>;

/// Optimized template layout with indices for fast querying
#[derive(Debug, Default)]
pub struct OptimizedTemplateLayout {
    /// All files in a flat vector for efficient storage
    files: Vec<TemplateFile>,

    /// Index from template name to file indices
    template_index: HashMap<String, Vec<usize>>,

    /// Indices for each entity type (entity_key -> value -> file_indices)
    entity_indices: HashMap<String, EntityIndex>,

    /// Index for suffixes
    suffix_index: HashMap<String, Vec<usize>>,

    /// Index for extensions
    extension_index: HashMap<String, Vec<usize>>,

    /// Template metadata
    metadata: HashMap<String, TemplateMetadata>,
}

impl OptimizedTemplateLayout {
    /// Create a new empty layout
    pub fn new() -> Self {
        Self::default()
    }

    /// Add a file to the layout and update all indices
    pub fn add_file(&mut self, file: TemplateFile) {
        let file_idx = self.files.len();

        // Update template index
        self.template_index
            .entry(file.template.to_string())
            .or_insert_with(Vec::new)
            .push(file_idx);

        // Update entity indices
        for (key, value) in file.entities.iter() {
            self.entity_indices
                .entry(key.clone())
                .or_insert_with(HashMap::new)
                .entry(value.clone())
                .or_insert_with(Vec::new)
                .push(file_idx);
        }

        // Update suffix index
        if let Some(suffix) = &file.suffix {
            self.suffix_index
                .entry(suffix.to_string())
                .or_insert_with(Vec::new)
                .push(file_idx);
        }

        // Update extension index
        if let Some(extension) = &file.extension {
            self.extension_index
                .entry(extension.to_string())
                .or_insert_with(Vec::new)
                .push(file_idx);
        }

        // Add the file
        self.files.push(file);
    }

    /// Get all templates
    pub fn get_templates(&self) -> Vec<&str> {
        let mut templates: Vec<&str> = self.template_index.keys().map(|s| s.as_str()).collect();
        templates.sort_unstable();
        templates
    }

    /// Get files for a specific template
    pub fn get_template_files(&self, template: &str) -> Option<Vec<&TemplateFile>> {
        self.template_index.get(template).map(|indices| {
            indices.iter().map(|&idx| &self.files[idx]).collect()
        })
    }

    /// Optimized query using indices
    pub fn query_optimized(&self, query: &HashMap<String, String>) -> Vec<&TemplateFile> {
        if query.is_empty() {
            return self.files.iter().collect();
        }

        // Start with the most selective index
        let mut result_indices: Option<HashSet<usize>> = None;

        // Process each query parameter
        for (key, value) in query {
            let indices = match key.as_str() {
                "tpl" => self.template_index.get(value).cloned(),
                "suffix" => self.suffix_index.get(value).cloned(),
                "extension" => self.extension_index.get(value).cloned(),
                _ => {
                    self.entity_indices
                        .get(key)
                        .and_then(|entity_map| entity_map.get(value))
                        .cloned()
                }
            };

            if let Some(idx_vec) = indices {
                let idx_set: HashSet<usize> = idx_vec.into_iter().collect();

                match &mut result_indices {
                    None => result_indices = Some(idx_set),
                    Some(current) => {
                        // Intersection with current results
                        *current = current.intersection(&idx_set).cloned().collect();
                    }
                }
            } else {
                // No files match this criterion
                return Vec::new();
            }
        }

        // Convert indices to files
        if let Some(indices) = result_indices {
            let mut results: Vec<&TemplateFile> = indices
                .into_iter()
                .map(|idx| &self.files[idx])
                .collect();
            results.sort_by_key(|f| &f.path);
            results
        } else {
            Vec::new()
        }
    }

    /// Add metadata for a template
    pub fn add_metadata(&mut self, template: &str, metadata: TemplateMetadata) {
        self.metadata.insert(template.to_string(), metadata);
    }

    /// Get metadata for a specific template
    pub fn get_metadata(&self, template: &str) -> Option<&TemplateMetadata> {
        self.metadata.get(template)
    }
}

/// Parse the templateflow skeleton from a zip file with optimizations
pub fn parse_skeleton_optimized<R: std::io::Read + std::io::Seek>(reader: R) -> Result<OptimizedTemplateLayout> {
    use zip::ZipArchive;
    use std::io::Read;

    let mut archive = ZipArchive::new(reader)
        .map_err(|e| TemplateFlowError::IoError(e.into()))?;

    let mut layout = OptimizedTemplateLayout::new();
    let mut metadata_files = HashMap::new();

    // Pre-allocate based on archive size
    layout.files.reserve(archive.len());

    // First pass: collect all files and metadata
    for i in 0..archive.len() {
        let mut file = archive.by_index(i)
            .map_err(|e| TemplateFlowError::IoError(e.into()))?;

        let path = PathBuf::from(file.name());

        // Skip directories
        if file.is_dir() {
            continue;
        }

        // Check if path is within a template directory
        let components: Vec<_> = path.components().collect();
        if components.is_empty() {
            continue;
        }

        // Get the first component (should be template directory)
        let first_component = components[0].as_os_str().to_str().unwrap_or("");
        if !first_component.starts_with("tpl-") {
            continue;
        }

        // Check if this is a template_description.json file
        if path.file_name() == Some(std::ffi::OsStr::new("template_description.json")) {
            if let Some(parent) = path.parent() {
                if let Some(parent_name) = parent.file_name() {
                    if let Some(template_name) = parent_name.to_str() {
                        if template_name.starts_with("tpl-") {
                            let template = template_name.strip_prefix("tpl-").unwrap();
                            let mut content = String::new();
                            file.read_to_string(&mut content)
                                .map_err(|e| TemplateFlowError::IoError(e))?;
                            metadata_files.insert(template.to_string(), content);
                        }
                    }
                }
            }
        } else {
            // Try to parse as a template file
            if let Ok(template_file) = TemplateFile::from_path(&path) {
                layout.add_file(template_file);
            }
        }
    }

    // Second pass: parse metadata files
    for (template, json_content) in metadata_files {
        if let Ok(metadata) = TemplateMetadata::from_json(&json_content) {
            layout.add_metadata(&template, metadata);
        }
    }

    Ok(layout)
}

/// Load the skeleton from a file path
pub fn load_skeleton_from_file_optimized(path: &Path) -> Result<OptimizedTemplateLayout> {
    use std::fs::File;

    let file = File::open(path)?;
    parse_skeleton_optimized(file)
}

/// Load the skeleton from bytes
pub fn load_skeleton_from_bytes_optimized(bytes: &[u8]) -> Result<OptimizedTemplateLayout> {
    use std::io::Cursor;

    let cursor = Cursor::new(bytes);
    parse_skeleton_optimized(cursor)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_optimized_query_performance() {
        // Create a layout with many files
        let mut layout = OptimizedTemplateLayout::new();

        // Add 1000 files across 10 templates
        for template_idx in 0..10 {
            let template = format!("Template{}", template_idx);
            for res in 1..=10 {
                for suffix in &["T1w", "T2w", "mask", "brain"] {
                    let path = PathBuf::from(format!(
