        query.insert("suffix".to_string(), "mask".to_string());
        let results = layout.query_optimized(&query);
        assert_eq!(results.len(), 10); // 10 resolutions
    }

    #[test]
    fn test_memory_efficiency() {
        let path1 = PathBuf::from("tpl-MNI152Lin/tpl-MNI152Lin_res-01_T1w.nii.gz");
        let path2 = PathBuf::from("tpl-MNI152Lin/tpl-MNI152Lin_res-02_T1w.nii.gz");

        let file1 = TemplateFile::from_path(&path1).unwrap();
        let file2 = TemplateFile::from_path(&path2).unwrap();

        // Template names should share the same Arc
