//! # TemplateFlow
//!
//! A Rust client for accessing standardized brain templates from TemplateFlow.
//!
//! TemplateFlow provides access to a library of standardized brain templates
//! used in neuroimaging research. This crate provides a Rust interface to
//! download and query these templates following the Brain Imaging Data Structure
//! (BIDS) specification.
//!
//! ## Features
//!
//! - 🧠 Access to 30+ standardized brain templates
//! - 📁 BIDS-compliant organization and querying
//! - ⚡ Fast S3-based downloads with progress tracking
//! - 💾 Smart local caching with integrity checking
//! - 🔍 Flexible query system for finding specific files
//! - 🚀 Both synchronous and asynchronous APIs
//! - 🛠️ Command-line interface for easy access
//!
//! ## Quick Start
//!
//! ```rust,no_run
//! use templateflow::{get, ls, templates};
//! use std::collections::HashMap;
//!
//! # fn main() -> Result<(), Box<dyn std::error::Error>> {
//! // List all available templates
//! let all_templates = templates(None)?;
//! println!("Found {} templates", all_templates.len());
//!
//! // List files for a specific template with query
//! let mut query = HashMap::new();
//! query.insert("resolution".to_string(), "1".to_string());
//! query.insert("suffix".to_string(), "T1w".to_string());
//! 
//! let files = ls("MNI152Lin", Some(&query))?;
//! println!("Found {} matching files", files.len());
//!
//! // Download the files
//! let downloaded = get("MNI152Lin", Some(&query))?;
//! println!("Downloaded to: {:?}", downloaded);
//! # Ok(())
//! # }
//! ```
//!
//! ## Async Example
//!
//! ```rust,no_run
//! use templateflow::get_multiple_async;
//! use std::collections::HashMap;
//!
//! # async fn example() -> Result<(), Box<dyn std::error::Error>> {
//! // Download multiple files concurrently
//! let mut query = HashMap::new();
//! query.insert("atlas".to_string(), "AAL".to_string());
//! 
//! let files = get_multiple_async("MNI152NLin2009cAsym", Some(&query)).await?;
//! println!("Downloaded {} atlas files", files.len());
//! # Ok(())
//! # }
//! ```
//!
//! ## Configuration
//!
//! TemplateFlow can be configured using environment variables:
//!
//! - `TEMPLATEFLOW_HOME`: Cache directory (default: `~/.cache/templateflow`)
//! - `TEMPLATEFLOW_S3_ROOT`: S3 bucket URL
//! - `TEMPLATEFLOW_AUTOUPDATE`: Auto-update skeleton index
//! - `TEMPLATEFLOW_TIMEOUT`: HTTP timeout in seconds
//!
//! ## BIDS Entities
//!
//! Query templates using BIDS entities:
//! - `resolution` / `res`: Spatial resolution (e.g., "1", "2")
//! - `suffix`: File type (e.g., "T1w", "mask", "brain")
//! - `atlas`: Atlas name (e.g., "AAL", "Schaefer2018")
//! - `hemisphere` / `hemi`: Brain hemisphere ("L" or "R")
//! - `description` / `desc`: Description label
//! - And more...

// Public modules
pub mod error;
pub mod config;
pub mod s3;
pub mod cache;
pub mod bids;
pub mod api;
pub mod cli;

// Re-export commonly used types
pub use error::{TemplateFlowError, Result};
pub use config::Config;
pub use bids::TemplateMetadata;

// Re-export API functions
pub use api::{get, get_metadata, get_citations, ls, templates};
// Re-export async API functions
pub use api::{get_async, get_multiple_async, get_multiple_async_advanced, ParallelDownloadOptions};

