use criterion::{black_box, criterion_group, criterion_main, Criterion, BenchmarkId};
use std::collections::HashMap;
use templateflow::bids::{TemplateLayout, load_skeleton_from_file};
use std::path::Path;

// Only include optimized benchmarks if feature is enabled
#[cfg(feature = "optimized-bids")]
use templateflow::bids_optimized::{OptimizedTemplateLayout, load_skeleton_from_file_optimized};

fn load_test_layout() -> TemplateLayout {
    let skeleton_path = Path::new("templateflow-skel.zip");
    load_skeleton_from_file(skeleton_path).expect("Failed to load skeleton")
}

#[cfg(feature = "optimized-bids")]
fn load_test_layout_optimized() -> OptimizedTemplateLayout {
    let skeleton_path = Path::new("templateflow-skel.zip");
    load_skeleton_from_file_optimized(skeleton_path).expect("Failed to load skeleton")
}

fn benchmark_query_single_entity(c: &mut Criterion) {
    let layout = load_test_layout();

    c.bench_function("original_query_single_entity", |b| {
        let mut query = HashMap::new();
        query.insert("res".to_string(), "01".to_string());

        b.iter(|| {
            let results = layout.query(black_box(&query));
            black_box(results.len());
        });
    });

    #[cfg(feature = "optimized-bids")]
    {
        let layout_opt = load_test_layout_optimized();

        c.bench_function("optimized_query_single_entity", |b| {
            let mut query = HashMap::new();
            query.insert("res".to_string(), "01".to_string());

            b.iter(|| {
                let results = layout_opt.query_optimized(black_box(&query));
                black_box(results.len());
            });
        });
    }
}

fn benchmark_query_multiple_entities(c: &mut Criterion) {
    let layout = load_test_layout();

    c.bench_function("original_query_multiple_entities", |b| {
        let mut query = HashMap::new();
        query.insert("tpl".to_string(), "MNI152Lin".to_string());
        query.insert("res".to_string(), "01".to_string());
        query.insert("suffix".to_string(), "T1w".to_string());

        b.iter(|| {
            let results = layout.query(black_box(&query));
            black_box(results.len());
        });
    });

    #[cfg(feature = "optimized-bids")]
    {
        let layout_opt = load_test_layout_optimized();

        c.bench_function("optimized_query_multiple_entities", |b| {
            let mut query = HashMap::new();
            query.insert("tpl".to_string(), "MNI152Lin".to_string());
            query.insert("res".to_string(), "01".to_string());
            query.insert("suffix".to_string(), "T1w".to_string());

            b.iter(|| {
                let results = layout_opt.query_optimized(black_box(&query));
                black_box(results.len());
            });
        });
    }
}

fn benchmark_query_all_templates(c: &mut Criterion) {
    let layout = load_test_layout();

