//! Example demonstrating query performance improvements with the optimized BIDS module
//!
//! Run with: cargo run --example query_performance
//! Run with optimized: cargo run --example query_performance --features optimized-bids

use std::collections::HashMap;
use std::time::Instant;
use templateflow::bids::{load_skeleton_from_file, TemplateLayout};

#[cfg(feature = "optimized-bids")]
use templateflow::bids_optimized::{load_skeleton_from_file_optimized, OptimizedTemplateLayout};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("TemplateFlow Query Performance Comparison");
    println!("========================================\n");

    // Load skeleton
    let skeleton_path = std::path::Path::new("templateflow-skel.zip");
    if !skeleton_path.exists() {
        eprintln!("Error: templateflow-skel.zip not found. Please run update first.");
        std::process::exit(1);
    }

    // Benchmark original implementation
    println!("Loading skeleton (original implementation)...");
    let start = Instant::now();
    let layout = load_skeleton_from_file(skeleton_path)?;
    let load_time = start.elapsed();
    println!("  Load time: {:?}", load_time);
    println!("  Templates: {}", layout.templates.len());
    let total_files: usize = layout.templates.values().map(|v| v.len()).sum();
    println!("  Total files: {}\n", total_files);

    // Run queries with original implementation
    benchmark_original(&layout);

    // Benchmark optimized implementation if feature is enabled
    #[cfg(feature = "optimized-bids")]
    {
        println!("\nLoading skeleton (optimized implementation)...");
        let start = Instant::now();
        let layout_opt = load_skeleton_from_file_optimized(skeleton_path)?;
        let load_time_opt = start.elapsed();
        println!("  Load time: {:?}", load_time_opt);
        println!("  Templates: {}", layout_opt.get_templates().len());
        println!("  Speedup: {:.2}x\n", load_time.as_secs_f64() / load_time_opt.as_secs_f64());

        benchmark_optimized(&layout_opt);
    }

    #[cfg(not(feature = "optimized-bids"))]
    {
        println!("\nNote: Run with --features optimized-bids to see optimized performance");
    }

    Ok(())
}

fn benchmark_original(layout: &TemplateLayout) {
    println!("Query Benchmarks (original):");
    println!("---------------------------");

    // Query 1: Single entity (all files with res=01)
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());

    let start = Instant::now();
    let results = layout.query(&query);
    let duration = start.elapsed();
    println!("  Query: res=01");
    println!("    Results: {} files", results.len());
    println!("    Time: {:?}", duration);

    // Query 2: Multiple entities
    let mut query = HashMap::new();
    query.insert("tpl".to_string(), "MNI152Lin".to_string());
    query.insert("res".to_string(), "01".to_string());
    query.insert("suffix".to_string(), "T1w".to_string());

    let start = Instant::now();
    let results = layout.query(&query);
    let duration = start.elapsed();
    println!("\n  Query: tpl=MNI152Lin, res=01, suffix=T1w");
    println!("    Results: {} files", results.len());
    println!("    Time: {:?}", duration);

    // Query 3: All templates with a specific suffix
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "T1w".to_string());

    let start = Instant::now();
    let results = layout.query(&query);
    let duration = start.elapsed();
    println!("\n  Query: suffix=T1w (all templates)");
    println!("    Results: {} files", results.len());
    println!("    Time: {:?}", duration);

    // Query 4: Complex query
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());
    query.insert("desc".to_string(), "brain".to_string());

    let start = Instant::now();
    let results = layout.query(&query);
    let duration = start.elapsed();
    println!("\n  Query: suffix=mask, desc=brain");
    println!("    Results: {} files", results.len());
    println!("    Time: {:?}", duration);

    // Run 1000 queries to get average
    let mut total_duration = std::time::Duration::ZERO;
    for _ in 0..1000 {
        let mut query = HashMap::new();
        query.insert("res".to_string(), "01".to_string());
        query.insert("suffix".to_string(), "T1w".to_string());

        let start = Instant::now();
        let _ = layout.query(&query);
        total_duration += start.elapsed();
    }
    println!("\n  1000 queries (res=01, suffix=T1w):");
    println!("    Average time: {:?}", total_duration / 1000);
}

#[cfg(feature = "optimized-bids")]
fn benchmark_optimized(layout: &OptimizedTemplateLayout) {
    println!("Query Benchmarks (optimized):");
    println!("----------------------------");

    // Query 1: Single entity (all files with res=01)
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());

    let start = Instant::now();
