    let duration = start.elapsed();
    println!("\n  Query: suffix=T1w (all templates)");
    println!("    Results: {} files", results.len());
    println!("    Time: {:?}", duration);

    // Query 4: Complex query
    let mut query = HashMap::new();
    query.insert("suffix".to_string(), "mask".to_string());
    query.insert("desc".to_string(), "brain".to_string());

    let start = Instant::now();
    let results = layout.query_optimized(&query);
    let duration = start.elapsed();
    println!("\n  Query: suffix=mask, desc=brain");
    println!("    Results: {} files", results.len());
    println!("    Time: {:?}", duration);

    // Run 1000 queries to get average
    let mut total_duration = std::time::Duration::ZERO;
    for _ in 0..1000 {
        let mut query = HashMap::new();
        query.insert("res".to_string(), "01".to_string());
